const events = $input.first().json.events || [];
const ligasPermitidas = [
  'Chilean Primera',
  'Copa Libertadores',
  'Copa Sudamericana',
  'UEFA Champions League',
  'English Premier League',
  'Spanish La Liga'
];

const filtered = events.filter(e => 
  ligasPermitidas.some(liga => 
    (e.strLeague || '').toLowerCase().includes(liga.toLowerCase())
  )
);

return filtered.map(e => ({
  json: {
    idEvent: e.idEvent,
    homeTeam: e.strHomeTeam,
    awayTeam: e.strAwayTeam,
    league: e.strLeague,
    date: e.dateEvent,
    time: e.strTime
  }
}));

