const response = $input.first().json;
const text = response.content[0].text;

try {
  const article = JSON.parse(text);
  article.fecha = $input.first().json.date || new Date().toISOString().split('T')[0];
  article.equipos = [$input.first().json.homeTeam, $input.first().json.awayTeam];
  article.liga = $input.first().json.league;
  return [{ json: article }];
} catch(e) {
  // Try to extract JSON from text
  const match = text.match(/\{[\s\S]*\}/);
  if (match) {
    const article = JSON.parse(match[0]);
    article.fecha = new Date().toISOString().split('T')[0];
    return [{ json: article }];
  }
  throw new Error('Failed to parse article JSON: ' + e.message);
}
